#[frame_support::pallet]
pub mod pallet {
	use sp_std::collections::btree_set::BTreeSet;

	use super::WeightInfo;
	use frame_support::{
		inherent::Vec,
		pallet_prelude::{Encode, *},
		traits::tokens::nonfungibles_v2::{Create, Inspect, InspectEnumerable, Mutate},
		PalletId,
	};
	use pallet_nfts::{
		CollectionConfig, CollectionSettings, Config as NftsConfig, ItemConfig, ItemSettings,
		MintSettings, MintType, Pallet as NftsPallet,
	};
	use sp_runtime::traits::AccountIdConversion;

	const PERMISSION_KEY: &[u8] = b"permission";

	#[pallet::pallet]
	pub struct Pallet<T>(_);

	/// Configure the pallet by specifying the parameters and types on which it depends.
	#[pallet::config]
	pub trait Config: frame_system::Config + NftsConfig {
		/// Because this pallet emits events, it depends on the runtime's definition of an event.
		type RuntimeEvent: From<Event<Self>> + IsType<<Self as frame_system::Config>::RuntimeEvent>;

		#[pallet::constant]
		type PalletId: Get<PalletId>;

		type Permission: MaybeSerializeDeserialize;

		/// Type representing the weight of this pallet
		type WeightInfo: WeightInfo;
	}

	#[pallet::storage]
	#[pallet::getter(fn collection_id)]
	pub type CollectionId<T: Config> = StorageValue<_, <T as NftsConfig>::CollectionId>;

	#[pallet::storage]
	#[pallet::getter(fn pallet_account_id)]
	pub type PalletAccountId<T: Config> = StorageValue<_, T::AccountId>;

	#[pallet::event]
	#[pallet::generate_deposit(pub(super) fn deposit_event)]
	pub enum Event<T: Config> {
		PermissionCollectionCreated(<T as NftsConfig>::CollectionId),
	}

	#[pallet::error]
	pub enum Error<T> {
		NotInitialized,
	}

	#[pallet::genesis_config]
	pub struct GenesisConfig<T: Config> {
		pub initial_permission_holders: Vec<(T::AccountId, T::Permission)>,
	}

	#[cfg(feature = "std")]
	impl<T: Config> Default for GenesisConfig<T> {
		fn default() -> Self {
			Self { initial_permission_holders: vec![] }
		}
	}

	#[pallet::genesis_build]
	impl<T: Config> GenesisBuild<T> for GenesisConfig<T>
	where
		<T as NftsConfig>::ItemId: TryFrom<usize>,
		T::Permission: Encode,
	{
		fn build(&self) {
			let admin: T::AccountId = T::PalletId::get().into_account_truncating();
			PalletAccountId::<T>::put(admin.clone());

			let collection_id = NftsPallet::<T>::create_collection(
				&admin,
				&admin,
				&CollectionConfig {
					settings: CollectionSettings::default(),
					max_supply: None,
					mint_settings: MintSettings {
						mint_type: MintType::Issuer,
						price: None,
						start_block: None,
						end_block: None,
						default_item_settings: ItemSettings::default(),
					},
				},
			)
			.expect("could create collection");

			CollectionId::<T>::put(collection_id);

			for (idx, (holder, permission)) in self.initial_permission_holders.iter().enumerate() {
				let item_id = idx.try_into().ok().expect("could convert index to ItemId");

				NftsPallet::<T>::mint_into(
					&collection_id,
					&item_id,
					holder,
					&ItemConfig::default(),
					true,
				)
				.expect("could mint new permission nft");

				permission.using_encoded(|permission| {
					<NftsPallet<T> as Mutate<_, _>>::set_attribute(
						&collection_id,
						&item_id,
						PERMISSION_KEY,
						permission,
					)
					.expect("could set attribute");
				});
			}
		}
	}

	impl<T: Config> Pallet<T> {
		/// Returns an iterator over the accounts who have the
		/// permission provided according to their nfts.
		///
		/// # Errors
		/// This function will return an error if the pallet has not been initialized yet.
		pub fn permission_holders(
			permission: &T::Permission,
		) -> Result<BTreeSet<T::AccountId>, DispatchError>
		where
			T::Permission: Encode,
		{
			Self::collection_id()
				.map(|collection_id| {
					let permission = permission.encode();
					<NftsPallet<T>>::items(&collection_id)
						.filter_map(move |item_id| {
							NftsPallet::<T>::system_attribute(
								&collection_id,
								&item_id,
								PERMISSION_KEY,
							)
							.filter(|p| *p == permission)
							.and(NftsPallet::<T>::owner(collection_id, item_id))
						})
						.collect()
				})
				.ok_or(Error::<T>::NotInitialized.into())
		}

		/// Check if an account has the provided permission
		///
		/// # Errors
		/// This function will return an error if the pallet has not been initialized yet.
		pub fn check_permission(
			account_id: &T::AccountId,
			permission: &T::Permission,
		) -> Result<bool, DispatchError>
		where
			T::Permission: Encode,
		{
			Self::collection_id()
				.map(|collection_id| {
					let permission = permission.encode();
					NftsPallet::<T>::owned_in_collection(&collection_id, account_id).any(
						|item_id| {
							NftsPallet::<T>::system_attribute(
								&collection_id,
								&item_id,
								PERMISSION_KEY,
							)
							.is_some_and(|p| p == permission)
						},
					)
				})
				.ok_or(Error::<T>::NotInitialized.into())
		}
	}
}
